      self.key = key
      self.children = []

class Solution:\n   def __init__(self):
      self.root = Node(None)

   def getNode(self, root, key):
      for node in root.children:
         if node.key == key:
            return node
      return None

   def getChildren(self, root):
      return root.children

   def insert(self, word):
      node = self.root
      for c in word:
         found = False
         for child in node.children:
            if child.key == c:
               node = child
               found = True
               break
         if not found:
            node.children.append(Node(c))
            node = node.children[-1]
   def main(self):
      T = int(input())
      self.root = Node(None)
      for t in range(T):
         word = input()
         self.insert(word)
      return

