// C++ solution\n#include <iostream>
#include <vector>
#include <string>\n\nclass Node {
public:\n   char key;
   std::vector<Node*> children;

   Node(char key) : key(key), children() {}
};

class Solution {
public:\n   Node* root;

   Node* getNode(Node* root, char key) {
      for (Node* node : root->children) {
         if (node->key == key) {
            return node;
         }
      }
      return nullptr;
   }

   std::vector<Node*>& getChildren(Node* root) {
      return root->children;
   }

   void insert(std::string word) {
      Node* node = root;
      for (char c : word) {
         Node* found = nullptr;
         for (Node* child : getChildren(node)) {
            if (child->key == c) {
               node = child;
               found = child;
               break;
            }
         }
         if (!found) {
            getChildren(node).push_back(new Node(c));
            node = getChildren(node).back();
         }
      }
   }

   void main() {
      int T;
      std::cin >> T;
      root = new Node(nullptr);
      for (int t = 0; t < T; ++t) {
         std::string word;
         std::cin >> word;
         insert(word);
      }
   }
};

